import { tool } from "@opencode-ai/plugin"
import { spawn } from "node:child_process"
import { existsSync } from "node:fs"
import { access, readFile } from "node:fs/promises"
import { join } from "node:path"
import {
  currentArtifacts,
  defaultArtifactPath,
  getTicket,
  latestArtifact,
  loadArtifactRegistry,
  loadManifest,
  loadWorkflowState,
  normalizeRepoPath,
  registerArtifactSnapshot,
  requireBootstrapReady,
  rootPath,
  saveArtifactRegistry,
  saveManifest,
  writeText,
} from "../lib/workflow"

type PackageJson = {
  packageManager?: string
  scripts?: Record<string, string>
}

type CommandSpec = {
  label: string
  argv: string[]
  reason: string
  env_overrides?: Record<string, string>
}

type CommandResult = CommandSpec & {
  exit_code: number
  duration_ms: number
  stdout: string
  stderr: string
}

type PythonRunner = {
  label: string
  argv: string[]
  reason: string
}
type SmokeArgs = {
  ticket_id?: string
  scope?: string
